SELECT [GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code] AS Marchio, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code] AS Stagione, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Line Code] AS Linea, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_] AS Articolo, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01] AS CodiceColore, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status - Item] AS StatusArticolo, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status Date], [GraficoMiglioriArticoliVendutiEstrazione-step0].[Delete Reason] AS DeleteReasonVendite, Sum(Val(Nz([no_ of pairs]))) AS Paia, [GraficoMiglioriArticoliVendutiEstrazione-step1].Description AS Descrizione, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Description 2] AS Descrizione2, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Family] AS FamigliaProdotto, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Sex] AS GenereProdotto, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Collection Code] AS [Collection Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Vendor No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].VendorName, [GraficoMiglioriArticoliVendutiEstrazione-step1].Manufacturer, [GraficoMiglioriArticoliVendutiEstrazione-step1].ManufacturerName, [GraficoMiglioriArticoliVendutiEstrazione-step1].[advertising material], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Currency Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Country_Region of Origin Code] AS Espr1
FROM [GraficoMiglioriArticoliVendutiEstrazione-step1] LEFT JOIN [GraficoMiglioriArticoliVendutiEstrazione-step0] ON ([GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01] = [GraficoMiglioriArticoliVendutiEstrazione-step0].[Constant Variable Code]) AND ([GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_] = [GraficoMiglioriArticoliVendutiEstrazione-step0].No_)
GROUP BY [GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Line Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status - Item], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Sales_Purchase Status Date], [GraficoMiglioriArticoliVendutiEstrazione-step0].[Delete Reason], [GraficoMiglioriArticoliVendutiEstrazione-step1].Description, [GraficoMiglioriArticoliVendutiEstrazione-step1].[Description 2], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Family], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Product Sex], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Collection Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Vendor No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].VendorName, [GraficoMiglioriArticoliVendutiEstrazione-step1].Manufacturer, [GraficoMiglioriArticoliVendutiEstrazione-step1].ManufacturerName, [GraficoMiglioriArticoliVendutiEstrazione-step1].[advertising material], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Currency Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Country_Region of Origin Code]
HAVING ((([GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code])=[Maschere]![principale]![filtroMarchio]) AND (([GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code])=[Maschere]![principale]![filtroStagione]))
ORDER BY [GraficoMiglioriArticoliVendutiEstrazione-step1].[Trademark Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Season Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Line Code], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Model Item No_], [GraficoMiglioriArticoliVendutiEstrazione-step1].[Variable Code 01];

